import React, { useState } from 'react';
import DragDropCanvas from './components/DragDropCanvas';
import VisualizationLibrary from './components/VisualizationLibrary';
import ExportManager from './components/ExportManager';
import DataConnections from './components/DataConnections';
import VariablesView from './components/VariablesView';
import CodeEditor from './components/CodeEditor';
import BuilderPageTabs from './components/BuilderPageTabs';
import { WindowPanel, BackgroundConfig, DataConnection, CodeEditorConfig, BuilderPage } from './types';
import './App.css';

const App: React.FC = () => {
  // Builder pages state (only for the builder tab)
  const [builderPages, setBuilderPages] = useState<BuilderPage[]>([
    {
      id: 'page-1',
      name: 'Page 1',
      windows: [],
      backgroundConfig: {
        width: 1200,
        height: 800,
        color: '#ffffff'
      }
    }
  ]);
  const [activeBuilderPageId, setActiveBuilderPageId] = useState<string>('page-1');

  // Global state (shared across all pages)
  const [dataConnections, setDataConnections] = useState<DataConnection>({
    apiConnections: [],
    globalVariables: {}
  });
  const [activeTab, setActiveTab] = useState<'builder' | 'data' | 'variables' | 'editor'>('builder');
  const [leftPanelVisible, setLeftPanelVisible] = useState<boolean>(true);
  const [rightPanelVisible, setRightPanelVisible] = useState<boolean>(true);
  const [codeEditorConfigs, setCodeEditorConfigs] = useState<CodeEditorConfig[]>([
    {
      id: 'default-config',
      name: 'Default Editor',
      elements: [],
      htmlCode: '',
      jsCode: '',
      cssCode: ''
    }
  ]);

  // Expose builder pages to window object for navigation templates
  React.useEffect(() => {
    try {
      const showPage = (pageId: string) => {
        console.log('🎯 showPage called with:', pageId);
        setActiveBuilderPageId(pageId);
      };

      // Create individual page functions
      const pageFunctions: { [key: string]: () => void } = {};
      builderPages.forEach(page => {
        const functionName = `goTo${page.name.replace(/[^a-zA-Z0-9]/g, '')}`;
        pageFunctions[functionName] = () => {
          console.log(`🚀 ${functionName} called for page:`, page.id);
          setActiveBuilderPageId(page.id);
        };
      });

      // Expose to multiple window contexts for maximum accessibility
      const globalData = { 
        builderPages,
        showPage,
        ...pageFunctions
      };

      // Expose to main window
      Object.assign(window, globalData);

      // Also expose to parent window (if in iframe)
      if (window.parent && window.parent !== window) {
        Object.assign(window.parent, globalData);
      }

      // Expose to top window (if nested iframes)
      if (window.top && window.top !== window) {
        Object.assign(window.top, globalData);
      }

      // Create a global namespace for extra safety
      try {
        Object.defineProperty(window, 'webBuilderGlobals', { value: globalData, writable: true });
        if (window.parent && window.parent !== window) {
          Object.defineProperty(window.parent, 'webBuilderGlobals', { value: globalData, writable: true });
        }
        if (window.top && window.top !== window) {
          Object.defineProperty(window.top, 'webBuilderGlobals', { value: globalData, writable: true });
        }
      } catch (e) {
        console.log('Could not create webBuilderGlobals:', e);
      }

      console.log('✅ Exposed to window contexts:', {
        builderPages: builderPages.length,
        showPage: 'function',
        pageFunctions: Object.keys(pageFunctions),
        windowKeys: Object.keys(window).filter(k => k.startsWith('goTo')),
        webBuilderGlobals: 'object'
      });
    } catch (e) {
      console.log('Could not expose builderPages to window:', e);
    }
  }, [builderPages]);

  // Listen for navigation messages from templates
  React.useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'navigatePage' && event.data.pageId) {
        console.log('📨 Received navigation message:', event.data.pageId);
        setActiveBuilderPageId(event.data.pageId);
      }

      // Handle requests for page function data
      if (event.data && event.data.type === 'requestPageFunctions') {
        console.log('📨 Received request for page functions');
        const functionData = builderPages.map(page => ({
          id: page.id,
          name: page.name,
          functionName: `goTo${page.name.replace(/[^a-zA-Z0-9]/g, '')}`
        }));

        // Send function data back to the requesting iframe
        if (event.source && typeof event.source.postMessage === 'function') {
          event.source.postMessage({
            type: 'pageFunctionsResponse',
            functions: functionData
          }, '*');
        }
      }

      // Handle function calls from templates
      if (event.data && event.data.type === 'callPageFunction' && event.data.pageId) {
        console.log('📨 Received page function call:', event.data.pageId);
        setActiveBuilderPageId(event.data.pageId);
      }
    };

    const handleNavigationEvent = (event: any) => {
      if (event.detail && event.detail.pageId) {
        console.log('📨 Received navigation event:', event.detail.pageId);
        setActiveBuilderPageId(event.detail.pageId);
      }
    };

    window.addEventListener('message', handleMessage);
    document.addEventListener('pageNavigation', handleNavigationEvent);

    return () => {
      window.removeEventListener('message', handleMessage);
      document.removeEventListener('pageNavigation', handleNavigationEvent);
    };
  }, []);

  // Helper functions to get current page data
  const getCurrentBuilderPage = (): BuilderPage => {
    return builderPages.find(p => p.id === activeBuilderPageId) || builderPages[0];
  };

  // Computed values for current page
  const windows = getCurrentBuilderPage().windows;
  const backgroundConfig = getCurrentBuilderPage().backgroundConfig;

  // Builder page management functions
  const handleBuilderPageSelect = (pageId: string) => {
    setActiveBuilderPageId(pageId);
  };

  const handleBuilderPageAdd = () => {
    const newPageId = `page-${Date.now()}`;
    const newPage: BuilderPage = {
      id: newPageId,
      name: `Page ${builderPages.length + 1}`,
      windows: [],
      backgroundConfig: {
        width: 1200,
        height: 800,
        color: '#ffffff'
      }
    };
    setBuilderPages(prev => [...prev, newPage]);
    setActiveBuilderPageId(newPageId);
  };

  const handleBuilderPageRename = (pageId: string, newName: string) => {
    setBuilderPages(prev =>
      prev.map(page =>
        page.id === pageId ? { ...page, name: newName } : page
      )
    );
  };

  const handleBuilderPageDelete = (pageId: string) => {
    if (builderPages.length <= 1) return; // Don't delete the last page

    setBuilderPages(prev => {
      const remainingPages = prev.filter(page => page.id !== pageId);
      // If we're deleting the active page, switch to the first remaining page
      if (activeBuilderPageId === pageId) {
        setActiveBuilderPageId(remainingPages[0].id);
      }
      return remainingPages;
    });
  };

  // Updated setter functions to work with current page
  const setWindows = (newWindows: WindowPanel[] | ((prev: WindowPanel[]) => WindowPanel[])) => {
    setBuilderPages(prev =>
      prev.map(page =>
        page.id === activeBuilderPageId
          ? {
              ...page,
              windows: typeof newWindows === 'function' ? newWindows(page.windows) : newWindows
            }
          : page
      )
    );
  };

  const setBackgroundConfig = (newConfig: BackgroundConfig) => {
    setBuilderPages(prev =>
      prev.map(page =>
        page.id === activeBuilderPageId
          ? { ...page, backgroundConfig: newConfig }
          : page
      )
    );
  };

  const handleAddTemplate = (type: 'javascript' | 'html', template: any) => {
    const newWindow: WindowPanel = {
      id: `window-${Date.now()}`,
      title: template.name,
      type,
      content: type === 'html' ? template.code : '',
      position: { 
        x: Math.random() * 300 + 50, 
        y: Math.random() * 200 + 50 
      },
      size: { width: 400, height: 300 },
      jsCode: type === 'javascript' ? template.code : undefined
    };

    setWindows(prev => [...prev, newWindow]);
  };

  const handleWindowsChange = (newWindows: WindowPanel[]) => {
    setWindows(newWindows);
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      backgroundColor: '#f7f8fa',
      color: '#2c3e50'
    }}>
      {/* Header */}
      <header style={{
        padding: '15px 20px',
        backgroundColor: '#1a1a1a',
        color: 'white',
        borderBottom: '3px solid #0066cc',
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img 
            src="/evs-logo.png" 
            alt="EVS Automation" 
            style={{ 
              height: '65px', 
              width: 'auto'
            }} 
          />
          <div>
            <h1 style={{ 
              margin: 0, 
              fontSize: '28px',
              fontWeight: '700',
              letterSpacing: '0.5px',
              fontFamily: '"Segoe UI", "Arial Black", sans-serif'
            }}>
              Web App & HMI Builder
            </h1>
            <p style={{ 
              margin: '2px 0 0 0', 
              fontSize: '13px', 
              opacity: 0.85,
              fontWeight: '500',
              letterSpacing: '0.3px',
              textTransform: 'uppercase'
            }}>
              Industrial Web Applications & Data Visualization
            </p>
          </div>
        </div>
      </header>

      {/* Tab Navigation */}
      <div style={{
        borderBottom: '2px solid #e9ecef',
        backgroundColor: '#f1f3f4',
        boxShadow: 'inset 0 -1px 0 rgba(0,0,0,0.1)'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingLeft: '20px', paddingRight: '20px' }}>
          <div style={{ display: 'flex' }}>
            <button
              onClick={() => setActiveTab('builder')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'builder' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'builder' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'builder' ? '700' : '600',
                color: activeTab === 'builder' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              BUILDER
            </button>
            <button
              onClick={() => setActiveTab('data')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'data' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'data' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'data' ? '700' : '600',
                color: activeTab === 'data' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              DATA CONNECTIONS
            </button>
            <button
              onClick={() => setActiveTab('variables')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'variables' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'variables' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'variables' ? '700' : '600',
                color: activeTab === 'variables' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              VARIABLES
            </button>
            <button
              onClick={() => setActiveTab('editor')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'editor' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'editor' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'editor' ? '700' : '600',
                color: activeTab === 'editor' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              EDITOR
            </button>
          </div>

        </div>
      </div>

      {/* Main Layout */}
      <div style={{
        flex: 1,
        display: 'flex',
        overflow: 'hidden'
      }}>
        {activeTab === 'builder' ? (
          <>
            {/* Left Sidebar - Templates */}
            {leftPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f7f8fa',
                  borderRight: '2px solid #d6dbdf',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px',
                  boxShadow: 'inset -1px 0 0 rgba(0,102,204,0.1)'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '2px 0 12px rgba(0,102,204,0.15), inset -1px 0 0 rgba(0,102,204,0.2)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'inset -1px 0 0 rgba(0,102,204,0.1)';
                }}
              >
                {/* Clickable Tab Header */}
                <div 
                  onClick={() => setLeftPanelVisible(false)}
                  style={{
                    padding: '12px 16px',
                    backgroundColor: '#0066cc',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    borderBottom: '1px solid #d6dbdf',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none'
                  }}
                >
                  <span>TEMPLATES</span>
                  <span style={{ fontSize: '12px' }}>◀</span>
                </div>
                <VisualizationLibrary onAddTemplate={handleAddTemplate} />
              </div>
            )}

            {/* Left Panel Collapsed Tab */}
            {!leftPanelVisible && (
              <div 
                onClick={() => setLeftPanelVisible(true)}
                style={{
                  width: '32px',
                  backgroundColor: '#0066cc',
                  borderRight: '2px solid #d6dbdf',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  color: 'white',
                  fontSize: '14px',
                  fontWeight: '600',
                  writingMode: 'vertical-lr',
                  textOrientation: 'mixed',
                  fontFamily: '"Segoe UI", "Arial", sans-serif',
                  userSelect: 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span style={{ fontSize: '12px' }}>▶</span>
                  <span>TEMPLATES</span>
                </div>
              </div>
            )}

            {/* Center - Canvas */}
            <div style={{ 
              flex: 1, 
              display: 'flex',
              flexDirection: 'column',
              minWidth: '400px'
            }}>
              {/* Builder Page Tabs */}
              <BuilderPageTabs
                pages={builderPages}
                activePageId={activeBuilderPageId}
                onPageSelect={handleBuilderPageSelect}
                onPageAdd={handleBuilderPageAdd}
                onPageRename={handleBuilderPageRename}
                onPageDelete={handleBuilderPageDelete}
              />

              {/* Canvas Area */}
              <div style={{ 
                flex: 1, 
                overflow: 'auto'
              }}>
                <DragDropCanvas 
                windows={windows}
                onWindowsChange={handleWindowsChange}
                backgroundConfig={backgroundConfig}
                onBackgroundConfigChange={setBackgroundConfig}
                dataConnections={dataConnections}
              />
              </div>
            </div>

            {/* Right Sidebar - Export */}
            {rightPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f7f8fa',
                  borderLeft: '2px solid #d6dbdf',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px',
                  boxShadow: 'inset 1px 0 0 rgba(0,102,204,0.1)'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '-2px 0 12px rgba(0,102,204,0.15), inset 1px 0 0 rgba(0,102,204,0.2)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'inset 1px 0 0 rgba(0,102,204,0.1)';
                }}
              >
                {/* Clickable Tab Header */}
                <div 
                  onClick={() => setRightPanelVisible(false)}
                  style={{
                    padding: '12px 16px',
                    backgroundColor: '#0066cc',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    borderBottom: '1px solid #d6dbdf',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none'
                  }}
                >
                  <span>EXPORT</span>
                  <span style={{ fontSize: '12px' }}>▶</span>
                </div>
                <ExportManager 
                  builderPages={builderPages}
                  onBuilderPagesChange={setBuilderPages}
                  windows={windows} 
                  backgroundConfig={backgroundConfig}
                  onBackgroundConfigChange={setBackgroundConfig}
                  dataConnections={dataConnections}
                  onWindowsChange={setWindows}
                  onDataConnectionsChange={setDataConnections}
                  codeEditorConfigs={codeEditorConfigs}
                  onCodeEditorConfigsChange={setCodeEditorConfigs}
                />
              </div>
            )}

            {/* Right Panel Collapsed Tab */}
            {!rightPanelVisible && (
              <div 
                onClick={() => setRightPanelVisible(true)}
                style={{
                  width: '32px',
                  backgroundColor: '#0066cc',
                  borderLeft: '2px solid #d6dbdf',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  color: 'white',
                  fontSize: '14px',
                  fontWeight: '600',
                  writingMode: 'vertical-lr',
                  textOrientation: 'mixed',
                  fontFamily: '"Segoe UI", "Arial", sans-serif',
                  userSelect: 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span>EXPORT</span>
                  <span style={{ fontSize: '12px' }}>◀</span>
                </div>
              </div>
            )}
          </>
        ) : activeTab === 'data' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <DataConnections
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'variables' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <VariablesView
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'editor' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <CodeEditor
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
              configs={codeEditorConfigs}
              onConfigsChange={setCodeEditorConfigs}
            />
          </div>
        ) : null}
      </div>
    </div>
  );
};

export default App;
